// ============================================
// Health Check - Backend Monitoring
// ============================================
// Backend 노드의 상태 감시
// 헬스 체크, 자동 격리, 복구
//
// 작성: Claude Code AI (2026-03-02)
// 난이도: ⭐⭐⭐ 중급
// ============================================

// ============================================
// Part 1: 헬스 체크 기초
// ============================================

/// 헬스 체크 결과
struct HealthCheckResult {
  node_id: int,
  is_healthy: bool,
  response_time: int,      // ms
  last_check_time: int,
  consecutive_failures: int
}

/// 헬스 체크 설정
struct HealthCheckConfig {
  interval: int,           // ms (주기)
  timeout: int,            // ms
  unhealthy_threshold: int,  // 몇 번 실패하면 unhealthy로?
  healthy_threshold: int      // 몇 번 성공하면 healthy로?
}

/// 헬스 체크 초기화
fn init_health_check() -> HealthCheckConfig {
  println()
  println("🏥 Health Check Initialized")
  println("├─ Interval: 5000ms")
  println("├─ Timeout: 2000ms")
  println("├─ Unhealthy Threshold: 3")
  println("└─ Healthy Threshold: 2")

  return HealthCheckConfig {
    interval: 5000,
    timeout: 2000,
    unhealthy_threshold: 3,
    healthy_threshold: 2
  }
}

// ============================================
// Part 2: 헬스 체크 수행
// ============================================

/// Backend에 헬스 체크 요청 전송
fn check_backend_health(
  node_id: int,
  host: string,
  port: int,
  timeout: int
) -> HealthCheckResult {
  println()
  println("🔍 Health check on Node " + to_string(node_id))

  // 시뮬레이션: 90% 확률로 성공
  success_probability = 90
  random_value = random(0, 99)
  is_healthy = random_value < success_probability

  response_time = 50 + random(0, 100)  // 50-150ms

  result = HealthCheckResult {
    node_id: node_id,
    is_healthy: is_healthy,
    response_time: response_time,
    last_check_time: 0,
    consecutive_failures: 0
  }

  status_str = is_healthy ? "🟢 HEALTHY" : "🔴 UNHEALTHY"
  println("   Status: " + status_str)
  println("   Response Time: " + to_string(response_time) + "ms")

  return result
}

// ============================================
// Part 3: 상태 추적 및 결정
// ============================================

/// Backend 상태 업데이트
fn update_backend_health(
  backend: BackendServer,
  check_result: HealthCheckResult,
  config: HealthCheckConfig
) -> BackendServer {
  if check_result.is_healthy {
    // 성공: 연속 실패 카운트 리셋
    backend.connection_count = backend.connection_count + 1

    if backend.connection_count < 0 {
      backend.connection_count = 0
    }

    println("   ✅ Backend " + to_string(backend.node_id) + " is healthy")
  } else {
    // 실패: 연속 실패 카운트 증가
    backend.connection_count = backend.connection_count - 1

    println("   ❌ Backend " + to_string(backend.node_id) + " failed health check")

    // 연속 실패 횟수가 threshold 이상이면 비활성화
    if check_result.consecutive_failures >= config.unhealthy_threshold {
      backend.active = false
      println("   🔴 Backend " + to_string(backend.node_id) +
              " marked as INACTIVE")
    }
  }

  return backend
}

/// 비활성 Backend 복구 시도
fn attempt_recovery(
  backend: BackendServer,
  check_result: HealthCheckResult,
  config: HealthCheckConfig
) -> BackendServer {
  if !backend.active {
    // 비활성 Backend도 주기적으로 체크
    if check_result.is_healthy {
      // 성공 횟수 카운트
      consecutive_successes = 0  // 간단화된 구현

      if consecutive_successes >= config.healthy_threshold {
        backend.active = true
        println("   🟢 Backend " + to_string(backend.node_id) +
                " recovered and marked ACTIVE")
      }
    }
  }

  return backend
}

// ============================================
// Part 4: 일괄 헬스 체크
// ============================================

/// 모든 Backend에 헬스 체크 수행
fn perform_health_checks(
  backends: [BackendServer],
  config: HealthCheckConfig
) -> [BackendServer] {
  println()
  println("🏥 Performing health checks on " + to_string(len(backends)) +
          " backends")
  println("═══════════════════════════════════════")

  updated_backends = []

  for backend in backends {
    check_result = check_backend_health(
      backend.node_id,
      backend.host,
      backend.port,
      config.timeout
    )

    backend = update_backend_health(backend, check_result, config)
    backend = attempt_recovery(backend, check_result, config)

    updated_backends = updated_backends + [backend]
  }

  return updated_backends
}

// ============================================
// Part 5: 상태 보고
// ============================================

/// 헬스 체크 요약 출력
fn print_health_summary(backends: [BackendServer]) {
  println()
  println("📊 Health Check Summary")
  println("═══════════════════════════════════════")

  healthy_count = 0
  unhealthy_count = 0

  for backend in backends {
    if backend.active {
      healthy_count = healthy_count + 1
    } else {
      unhealthy_count = unhealthy_count + 1
    }
  }

  println()
  println("Healthy Backends: " + to_string(healthy_count))
  println("Unhealthy Backends: " + to_string(unhealthy_count))
  println()

  for backend in backends {
    status = backend.active ? "🟢 ACTIVE" : "🔴 INACTIVE"

    println("Node " + to_string(backend.node_id) + ": " + status)
    println("└─ Connections: " + to_string(backend.connection_count))
  }
}

// ============================================
// Part 6: 테스트
// ============================================

fn test_init_health_check() {
  config = init_health_check()

  assert config.interval == 5000
  assert config.timeout == 2000
  assert config.unhealthy_threshold == 3
  assert config.healthy_threshold == 2

  println("✅ test_init_health_check passed")
}

fn test_check_backend_health() {
  result = check_backend_health(0, "localhost", 9000, 2000)

  assert result.node_id == 0
  assert result.response_time >= 50
  assert result.is_healthy == true || result.is_healthy == false

  println("✅ test_check_backend_health passed")
}

fn test_update_backend_health_success() {
  backend = BackendServer {
    node_id: 0,
    host: "localhost",
    port: 9000,
    weight: 1,
    active: true,
    connection_count: 0,
    total_requests: 0,
    failed_requests: 0
  }

  check_result = HealthCheckResult {
    node_id: 0,
    is_healthy: true,
    response_time: 50,
    last_check_time: 0,
    consecutive_failures: 0
  }

  config = init_health_check()

  backend = update_backend_health(backend, check_result, config)

  assert backend.active == true

  println("✅ test_update_backend_health_success passed")
}

fn test_update_backend_health_failure() {
  backend = BackendServer {
    node_id: 0,
    host: "localhost",
    port: 9000,
    weight: 1,
    active: true,
    connection_count: 10,
    total_requests: 0,
    failed_requests: 0
  }

  check_result = HealthCheckResult {
    node_id: 0,
    is_healthy: false,
    response_time: 0,
    last_check_time: 0,
    consecutive_failures: 3
  }

  config = init_health_check()

  backend = update_backend_health(backend, check_result, config)

  // 연속 실패가 threshold 이상이면 inactive
  assert backend.active == false

  println("✅ test_update_backend_health_failure passed")
}

fn test_perform_health_checks() {
  backends = [
    BackendServer {
      node_id: 0,
      host: "localhost",
      port: 9000,
      weight: 1,
      active: true,
      connection_count: 0,
      total_requests: 0,
      failed_requests: 0
    },
    BackendServer {
      node_id: 1,
      host: "localhost",
      port: 9100,
      weight: 1,
      active: true,
      connection_count: 0,
      total_requests: 0,
      failed_requests: 0
    }
  ]

  config = init_health_check()

  updated = perform_health_checks(backends, config)

  assert len(updated) == 2

  println("✅ test_perform_health_checks passed")
}

fn test_print_health_summary() {
  backends = [
    BackendServer {
      node_id: 0,
      host: "localhost",
      port: 9000,
      weight: 1,
      active: true,
      connection_count: 5,
      total_requests: 100,
      failed_requests: 0
    },
    BackendServer {
      node_id: 1,
      host: "localhost",
      port: 9100,
      weight: 1,
      active: false,
      connection_count: 0,
      total_requests: 50,
      failed_requests: 10
    }
  ]

  print_health_summary(backends)

  println("✅ test_print_health_summary passed")
}

// ============================================
// 메인 테스트 실행
// ============================================

fn main() {
  println("🏥 Health Check - Tests")
  println("═════════════════════════════════")

  test_init_health_check()
  test_check_backend_health()
  test_update_backend_health_success()
  test_update_backend_health_failure()
  test_perform_health_checks()
  test_print_health_summary()

  println()
  println("✅ All health check tests passed!")
  println()
  println("📊 Summary:")
  println("├─ Health check execution: ✅")
  println("├─ Status tracking: ✅")
  println("├─ Failure detection: ✅")
  println("├─ Recovery attempt: ✅")
  println("└─ Monitoring: ✅")
}

// 실행
main()
